import { TypeQuizQuestion } from "./quiz-types";
export const newQAdvanced: TypeQuizQuestion[] = [
  // ── TYPE 1: The Reformer (IDs 1351–1360) ──
  { id: 1351, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 101, track2Day: 151, category: "Instinctual Variants", question: "A self-preservation Type 1 is most likely to channel their perfectionism into which area?", options: [{ letter: "A", text: "Maintaining a flawless social reputation and public image" }, { letter: "B", text: "Optimizing their diet, exercise routine, and living environment for ideal health" }, { letter: "C", text: "Seeking an intense, all-consuming romantic connection that meets their standards" }, { letter: "D", text: "Campaigning publicly for political or social reform" }], answer: "B", explanation: "SP Ones direct their reforming energy inward toward personal well-being. Naranjo describes them as the most anxious and worry-prone Ones, obsessing over getting daily routines 'right', the correct food, the proper sleep schedule, the ideal home environment." },
  { id: 1352, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 102, track2Day: 152, category: "Instinctual Variants", question: "Social Type 1s are sometimes called 'non-adaptable' in Enneagram literature. What does this mean in practice?", options: [{ letter: "A", text: "They refuse to attend social gatherings they find pointless" }, { letter: "B", text: "They become the rigid moral standard-bearer of their group, insisting the community uphold shared principles" }, { letter: "C", text: "They withdraw from groups that don't meet their intellectual standards" }, { letter: "D", text: "They adapt their personality to fit whatever group they're in" }], answer: "B", explanation: "Social Ones see themselves as guardians of collective ethics. Beatrice Chestnut notes they feel a compulsive need to model correct behavior for the group and can become preachy or rigid when they perceive the community straying from shared values." },
  { id: 1353, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 103, track2Day: 153, category: "Instinctual Variants", question: "Sexual (SX) Type 1s differ from the classic Type 1 image because they:", options: [{ letter: "A", text: "Show almost no anger and are extremely easygoing" }, { letter: "B", text: "Direct their reforming zeal toward their intimate partner, wanting to 'perfect' the relationship" }, { letter: "C", text: "Become withdrawn and detached from emotions" }, { letter: "D", text: "Abandon their principles entirely when in love" }], answer: "B", explanation: "SX Ones channel their drive for perfection into one-to-one bonds. They feel entitled to reform their partner and can oscillate between intense devotion and sharp criticism. Chestnut notes they often resemble Type 4s in their emotional intensity within relationships." },
  { id: 1354, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 104, track2Day: 154, category: "Wings in Practice", question: "A 1w9 (One with a Nine wing) manager receives a team proposal full of errors. How do they most likely respond compared to a 1w2?", options: [{ letter: "A", text: "The 1w9 quietly rewrites the proposal themselves; the 1w2 sits the team down to teach them how to do it correctly" }, { letter: "B", text: "The 1w9 angrily rejects it; the 1w2 accepts it to keep the peace" }, { letter: "C", text: "Both respond identically since wings don't affect behavior" }, { letter: "D", text: "The 1w9 delegates the fix to someone else; the 1w2 ignores it" }], answer: "A", explanation: "1w9s are more reserved and self-contained, they internalize their frustration and fix things silently. 1w2s, influenced by the Helper wing, feel compelled to directly engage others in improvement, making their corrections more interpersonal and instructive." },
  { id: 1355, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 105, track2Day: 155, category: "Wings in Practice", question: "Which mistyping is most common for a 1w2, and why?", options: [{ letter: "A", text: "Mistyped as Type 8, because they appear commanding and forceful" }, { letter: "B", text: "Mistyped as Type 2, because their helpfulness masks their inner critic as 'I know what's best for you'" }, { letter: "C", text: "Mistyped as Type 5, because they research topics exhaustively" }, { letter: "D", text: "Mistyped as Type 7, because they appear upbeat and optimistic" }], answer: "B", explanation: "1w2s often look like Twos because they channel their perfectionism into helping others improve. The key distinction: Twos help to be needed and loved, while 1w2s help because they genuinely see what's 'wrong' and feel morally obligated to fix it." },
  { id: 1356, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 106, track2Day: 156, category: "Integration Paths", question: "When a Type 1 integrates toward Type 7, what does healthy growth actually look like in daily life?", options: [{ letter: "A", text: "They become scattered and irresponsible, abandoning all structure" }, { letter: "B", text: "They learn to embrace spontaneity, find joy in imperfection, and allow themselves guilt-free pleasure" }, { letter: "C", text: "They become loud and attention-seeking at parties" }, { letter: "D", text: "They stop caring about ethics or quality altogether" }], answer: "B", explanation: "Integration to 7 doesn't mean becoming a Seven. It means the One accesses the Seven's gift of joy and presence. Riso-Hudson describe integrated Ones as discovering that life can be enjoyed, not just endured, they laugh more easily and accept 'good enough.'" },
  { id: 1357, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 107, track2Day: 157, category: "Integration Paths", question: "A Type 1 who has done significant growth work might surprise others by:", options: [{ letter: "A", text: "Becoming more rigid and principled under stress" }, { letter: "B", text: "Playfully laughing at their own mistakes and suggesting the group try something unplanned" }, { letter: "C", text: "Withdrawing completely from social obligations" }, { letter: "D", text: "Becoming excessively emotional and dramatic" }], answer: "B", explanation: "An integrating One accesses Seven's lightness. The hallmark is self-deprecating humor about their own perfectionism and a genuine willingness to deviate from plans. This signals the inner critic has softened, they can hold standards without being tyrannized by them." },
  { id: 1358, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 108, track2Day: 158, category: "Cross-System", question: "In MBTI terms, Type 1s most commonly test as which types, and what cognitive function drives this overlap?", options: [{ letter: "A", text: "ISTJ and ESTJ, extraverted Thinking (Te) mirrors the One's drive to organize the external world according to standards" }, { letter: "B", text: "INFP and ENFP, extraverted Intuition (Ne) mirrors the One's idealism" }, { letter: "C", text: "ISTP and ESTP, introverted Thinking (Ti) mirrors the One's analytical nature" }, { letter: "D", text: "INFJ and INTJ, introverted Intuition (Ni) mirrors the One's inner vision" }], answer: "A", explanation: "The One's structural perfectionism maps closely to Te, the function that creates systems, enforces standards, and organizes the external world. STJ types share the One's preference for rules, order, and measurable correctness. INTJ Ones exist but are less common." },
  { id: 1359, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 109, track2Day: 159, category: "Cross-System", question: "A Type 1 who is also an INFJ (Ni-Fe) would most likely differ from a typical ISTJ Type 1 in which way?", options: [{ letter: "A", text: "They would have no inner critic and be completely accepting" }, { letter: "B", text: "Their perfectionism would focus on idealistic visions for humanity rather than concrete procedural correctness" }, { letter: "C", text: "They would be indifferent to ethics and morality" }, { letter: "D", text: "They would be more spontaneous and disorganized" }], answer: "B", explanation: "An INFJ One channels their reforming drive through Ni-Fe: they envision how the world should be and feel personally responsible for guiding others toward that vision. Their standards are abstract and value-based rather than the ISTJ One's concrete and procedural standards." },
  { id: 1360, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 110, track2Day: 160, category: "Type Dynamics", question: "When a Type 1 and Type 4 are in a close relationship, what core tension typically emerges?", options: [{ letter: "A", text: "Both are too withdrawn to communicate" }, { letter: "B", text: "The One sees the Four as self-indulgent and undisciplined, while the Four sees the One as emotionally repressed and rigid" }, { letter: "C", text: "They compete for social status and external recognition" }, { letter: "D", text: "Both avoid conflict so problems never get addressed" }], answer: "B", explanation: "The 1-4 dynamic is a classic 'head vs. heart' tension. Ones suppress emotion in favor of principle; Fours dive into emotion as a source of identity. Each may secretly envy the other's strength: the One wishes they could feel freely, the Four wishes they had more self-discipline." },
  // ── TYPE 2: The Helper (IDs 1361–1370) ──
  { id: 1361, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 111, track2Day: 161, category: "Instinctual Variants", question: "A self-preservation Type 2 differs from the classic helper image because they:", options: [{ letter: "A", text: "Are openly demanding and vocal about their needs being met in return for help" }, { letter: "B", text: "Help others through providing physical comfort, cooking meals, creating a warm home, while struggling to ask for help themselves" }, { letter: "C", text: "Are completely self-sufficient and never help anyone" }, { letter: "D", text: "Focus exclusively on helping large organizations rather than individuals" }], answer: "B", explanation: "SP Twos are the counter-type: they resist appearing needy and instead express care through tangible, nurturing acts. Chestnut calls them 'privilege', they earn closeness by being indispensable caretakers while hiding their own vulnerability behind practical generosity." },
  { id: 1362, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 112, track2Day: 162, category: "Instinctual Variants", question: "Social Type 2s are sometimes described as the most ambitious subtype of Two. Why?", options: [{ letter: "A", text: "They seek power for its own sake and enjoy dominating others" }, { letter: "B", text: "They position themselves as influential connectors within groups, gaining status through who they know and who depends on them" }, { letter: "C", text: "They compete academically and professionally to prove they're the smartest" }, { letter: "D", text: "They withdraw from groups to pursue solo achievements" }], answer: "B", explanation: "Social Twos gain influence by becoming the indispensable hub of their social network. Naranjo links this to 'ambition', they cultivate relationships with powerful or important people, becoming the person everyone calls. Their identity comes from social centrality." },
  { id: 1363, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 113, track2Day: 163, category: "Instinctual Variants", question: "A sexual (SX) Type 2 at a party is most likely to:", options: [{ letter: "A", text: "Work the room helping everyone feel included equally" }, { letter: "B", text: "Focus intensely on one person they find compelling, using charm and emotional attunement to create immediate intimacy" }, { letter: "C", text: "Sit quietly in the corner observing the social dynamics" }, { letter: "D", text: "Organize the logistics of the event to make sure it runs smoothly" }], answer: "B", explanation: "SX Twos are the most seductive and emotionally intense subtype. They use their gift for reading people to create rapid, deep one-to-one bonds. Their attention is laser-focused on the chosen person, making that individual feel uniquely seen and valued." },
  { id: 1364, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 114, track2Day: 164, category: "Wings in Practice", question: "How does a 2w1 (Two with a One wing) typically express their helping differently from a 2w3?", options: [{ letter: "A", text: "The 2w1 helps out of moral duty and principled compassion; the 2w3 helps in visible, high-energy ways that others notice and applaud" }, { letter: "B", text: "The 2w1 helps only family; the 2w3 helps only strangers" }, { letter: "C", text: "The 2w1 is less emotional; the 2w3 is more emotional" }, { letter: "D", text: "There is no practical difference between the two wings" }], answer: "A", explanation: "2w1s are often called 'the Servant', their helping is quiet, principled, and tinged with moral obligation. 2w3s are 'the Host/Hostess', their helping is warm, energetic, and more publicly oriented. The 2w3 wants appreciation; the 2w1 wants to feel they did what was right." },
  { id: 1365, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 115, track2Day: 165, category: "Wings in Practice", question: "A 2w3 who loses their job is most likely to experience distress primarily because:", options: [{ letter: "A", text: "They fear financial ruin and homelessness" }, { letter: "B", text: "They lose a key platform for being seen as valuable and indispensable to others" }, { letter: "C", text: "They feel morally guilty for being fired" }, { letter: "D", text: "They no longer have alone time to recharge" }], answer: "B", explanation: "The Three wing amplifies the Two's need for external validation. A job provides both a helping role and an audience. Without it, the 2w3 loses their primary stage for demonstrating value, triggering a deep identity crisis around being needed and recognized." },
  { id: 1366, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 116, track2Day: 166, category: "Integration Paths", question: "When Type 2 integrates toward Type 4, what healthy shift occurs?", options: [{ letter: "A", text: "They become moody and self-absorbed" }, { letter: "B", text: "They develop the capacity to turn inward, acknowledge their own emotional needs, and express authentic creativity" }, { letter: "C", text: "They withdraw from all relationships" }, { letter: "D", text: "They become more critical and judgmental of others" }], answer: "B", explanation: "Integration to 4 gives Twos access to self-awareness and emotional honesty. Instead of only attending to others' feelings, they learn to sit with their own, discovering what they actually want beyond being needed. This often unlocks creative self-expression." },
  { id: 1367, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 117, track2Day: 167, category: "Integration Paths", question: "A Two who has genuinely integrated toward Four would handle a friend's crisis differently by:", options: [{ letter: "A", text: "Immediately dropping everything to fix the friend's problem as usual" }, { letter: "B", text: "Offering empathy while also honestly sharing their own feelings and boundaries about how much they can give" }, { letter: "C", text: "Ignoring the friend because they're focused on their own needs" }, { letter: "D", text: "Intellectualizing the friend's problem and offering detached advice" }], answer: "B", explanation: "An integrated Two maintains their compassion but adds Four's emotional honesty. They can say 'I care about you AND I need to take care of myself right now.' This vulnerability actually deepens relationships because it's authentic rather than martyring." },
  { id: 1368, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 118, track2Day: 168, category: "Cross-System", question: "Why are Type 2s disproportionately likely to test as ESFJ in the MBTI?", options: [{ letter: "A", text: "Extraverted Feeling (Fe), the drive to harmonize and attend to others' emotional states, directly mirrors the Two's core motivation" }, { letter: "B", text: "Introverted Sensing (Si) creates the Two's traditional caregiving role" }, { letter: "C", text: "Extraverted Thinking (Te) drives the Two's desire to organize help efficiently" }, { letter: "D", text: "Extraverted Intuition (Ne) makes Twos imaginative helpers" }], answer: "A", explanation: "Fe is the 'people-reading' function, it scans the emotional atmosphere and adjusts to maintain harmony. This maps directly to the Two's automatic attunement to others' needs. ESFJs and ENFJs share the Two's interpersonal warmth and desire to nurture social bonds." },
  { id: 1369, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 119, track2Day: 169, category: "Cross-System", question: "An ENTP Type 2 would be unusual because:", options: [{ letter: "A", text: "ENTPs cannot be any Enneagram type, the systems are incompatible" }, { letter: "B", text: "Ne-Ti prioritizes intellectual exploration and logical frameworks, creating tension with the Two's emotional focus on others' needs" }, { letter: "C", text: "ENTPs are always Type 7s by definition" }, { letter: "D", text: "Extraverts cannot be Type 2s" }], answer: "B", explanation: "While any MBTI type can be any Enneagram type, ENTP Twos are rare because Ne-Ti is oriented toward ideas and logical analysis rather than interpersonal caretaking. An ENTP Two might help through brainstorming solutions rather than emotional nurturing, making their Two-ness harder to spot." },
  { id: 1370, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 120, track2Day: 170, category: "Type Dynamics", question: "In a Type 2 and Type 5 relationship, what is the most common pattern of conflict?", options: [{ letter: "A", text: "Both are too emotionally expressive and overwhelm each other" }, { letter: "B", text: "The Two pursues emotional connection while the Five retreats, creating a chase-withdraw cycle" }, { letter: "C", text: "They compete for leadership and social dominance" }, { letter: "D", text: "Both avoid conflict so problems fester silently" }], answer: "B", explanation: "This is one of the Enneagram's most common and challenging pairings. The Two's strategy is to move toward others; the Five's is to move away. The more the Two reaches out, the more overwhelmed the Five feels. Palmer notes that breaking this cycle requires the Two to give space and the Five to initiate contact." },
  // ── TYPE 3: The Achiever (IDs 1371–1380) ──
  { id: 1371, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 121, track2Day: 171, category: "Instinctual Variants", question: "A self-preservation Type 3 often looks different from the stereotypical Three because they:", options: [{ letter: "A", text: "Are flashy, attention-seeking, and constantly promoting themselves" }, { letter: "B", text: "Work tirelessly behind the scenes to ensure material security, appearing more like a diligent Six or One than a showy Achiever" }, { letter: "C", text: "Avoid all forms of work and live off others' resources" }, { letter: "D", text: "Focus primarily on spiritual achievement rather than worldly success" }], answer: "B", explanation: "SP Threes are the counter-type. Chestnut describes them as 'vanity without vanity', they suppress the image-consciousness of the Three and instead pour energy into pragmatic efficiency. They want to be seen as hardworking and self-sufficient, not glamorous." },
  { id: 1372, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 122, track2Day: 172, category: "Instinctual Variants", question: "A social Type 3 is presenting at a conference. What internal experience is most likely driving them?", options: [{ letter: "A", text: "Genuine passion for the topic regardless of audience reaction" }, { letter: "B", text: "Acute awareness of how the audience perceives them, adjusting their delivery in real-time to maximize admiration and influence" }, { letter: "C", text: "Anxiety about being exposed as incompetent" }, { letter: "D", text: "Desire to finish quickly so they can network at the reception" }], answer: "B", explanation: "Social Threes are masters of reading a room. Their social instinct amplifies the Three's shapeshifting, they calibrate their persona to whatever the group values. Naranjo connects this to their core passion of vanity: they become a living advertisement for success as defined by their audience." },
  { id: 1373, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 123, track2Day: 173, category: "Instinctual Variants", question: "Sexual (SX) Type 3s are sometimes confused with Type 2s because they:", options: [{ letter: "A", text: "Are genuinely selfless and always put others first" }, { letter: "B", text: "Shape themselves to be maximally attractive and appealing to specific individuals, using charm and personal magnetism rather than résumé achievements" }, { letter: "C", text: "Have no ambition and prefer to stay in the background" }, { letter: "D", text: "Express their emotions more openly than any other Three subtype" }], answer: "B", explanation: "SX Threes achieve through personal allure rather than professional accomplishments. They promote themselves through attractiveness, charisma, and the ability to make individuals feel special. Unlike Twos, their motive is to be admired, not to be needed." },
  { id: 1374, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 124, track2Day: 174, category: "Wings in Practice", question: "What is the key behavioral difference between a 3w2 and a 3w4 at a networking event?", options: [{ letter: "A", text: "The 3w2 works the room with warmth and charm; the 3w4 is more selective, seeking deeper conversations with fewer people" }, { letter: "B", text: "The 3w2 avoids people; the 3w4 is the life of the party" }, { letter: "C", text: "Both behave identically in social settings" }, { letter: "D", text: "The 3w2 talks only about work; the 3w4 talks only about feelings" }], answer: "A", explanation: "The Two wing gives 3w2s interpersonal warmth and a wider social net, they want to be liked by many. The Four wing gives 3w4s a more nuanced, authentic edge, they curate a unique personal brand and prefer meaningful connection over mass approval." },
  { id: 1375, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 125, track2Day: 175, category: "Wings in Practice", question: "A 3w4 artist is most likely to struggle with which internal tension?", options: [{ letter: "A", text: "Wanting to create authentic, emotionally honest work while simultaneously needing it to be commercially successful and publicly acclaimed" }, { letter: "B", text: "Wanting to help others while needing personal space" }, { letter: "C", text: "Choosing between physical adventure and intellectual pursuits" }, { letter: "D", text: "Balancing social obligations with spiritual practice" }], answer: "A", explanation: "The 3w4 sits between achievement and authenticity. The Three core wants success and recognition; the Four wing craves genuine self-expression. This creates a painful oscillation: 'Am I making this because it's true or because it will sell?'" },
  { id: 1376, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 126, track2Day: 176, category: "Integration Paths", question: "When a Type 3 integrates toward Type 6, what healthy change emerges?", options: [{ letter: "A", text: "They become anxious and start doubting all their accomplishments" }, { letter: "B", text: "They develop genuine loyalty to others and commit to groups beyond personal gain, learning to value teamwork over individual glory" }, { letter: "C", text: "They stop working entirely and become passive" }, { letter: "D", text: "They become rule-following and rigid" }], answer: "B", explanation: "Integration to 6 gives Threes access to loyalty, vulnerability, and genuine commitment. Instead of viewing relationships as networking opportunities, they develop deep faithfulness. Riso-Hudson note that integrated Threes become courageous team players who inspire through authenticity, not image." },
  { id: 1377, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 127, track2Day: 177, category: "Integration Paths", question: "The hardest part of the Three's integration journey toward Six is:", options: [{ letter: "A", text: "Learning to work harder and achieve more" }, { letter: "B", text: "Allowing themselves to be seen as uncertain, vulnerable, or struggling, states that feel like failure to the Three's core identity" }, { letter: "C", text: "Becoming more organized and efficient" }, { letter: "D", text: "Learning to hide their emotions more effectively" }], answer: "B", explanation: "Six energy requires vulnerability and honest self-doubt, anathema to the Three's polished persona. Admitting 'I don't know' or 'I'm scared' feels like career suicide to an unintegrated Three. The growth edge is discovering that vulnerability creates deeper trust than any achievement." },
  { id: 1378, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 128, track2Day: 178, category: "Cross-System", question: "Type 3s often correlate with which MBTI types, and what function creates the overlap?", options: [{ letter: "A", text: "ENTJ and ESTJ, extraverted Thinking (Te) drives goal-oriented, results-focused behavior that mirrors the Three's achievement drive" }, { letter: "B", text: "INFP and ISFP, introverted Feeling (Fi) drives the Three's hidden emotional depth" }, { letter: "C", text: "INTP and ISTP, introverted Thinking (Ti) drives the Three's analytical precision" }, { letter: "D", text: "ENFP and ESFP, extraverted Intuition/Sensing drives the Three's spontaneity" }], answer: "A", explanation: "Te is the function of efficient execution, setting goals, measuring results, and optimizing systems. This maps directly to the Three's core drive. ENTJ and ESTJ Threes are especially common because Te dominance creates natural goal orientation and competitive drive." },
  { id: 1379, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 129, track2Day: 179, category: "Cross-System", question: "How might a Type 3 with strong introverted Feeling (Fi), such as an ISFP, manifest differently from the stereotypical Three?", options: [{ letter: "A", text: "They would have no drive to achieve and be completely passive" }, { letter: "B", text: "They would achieve in deeply personal, values-driven domains and measure success by internal authenticity rather than external metrics" }, { letter: "C", text: "They would be indistinguishable from any other ISFP" }, { letter: "D", text: "They would abandon their Three patterns entirely in favor of Fi values" }], answer: "B", explanation: "An ISFP Three still has the Three's achievement drive, but Fi redirects it inward. They might pursue mastery in art, craft, or personal expression where success means 'I created something true to myself.' They may resist the corporate ladder but still fiercely compete in their chosen domain." },
  { id: 1380, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 130, track2Day: 180, category: "Type Dynamics", question: "In a Type 3 and Type 9 partnership, what is the most common dynamic that develops over time?", options: [{ letter: "A", text: "The Three pushes the Nine to achieve more, while the Nine helps the Three slow down, but resentment builds when the Three sees the Nine as lazy and the Nine feels bulldozed" }, { letter: "B", text: "Both avoid all conflict and live in perfect harmony" }, { letter: "C", text: "The Nine dominates the relationship with strong opinions" }, { letter: "D", text: "Both compete intensely for career advancement" }], answer: "A", explanation: "This is one of the most common Enneagram pairings. Initially complementary, the Three admires the Nine's calm, the Nine admires the Three's drive, it can polarize. The Three may unconsciously carry all the ambition while the Nine merges with the Three's goals, losing their own identity." },
  // ── TYPE 4: The Individualist (IDs 1381–1390) ──
  { id: 1381, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 131, track2Day: 181, category: "Instinctual Variants", question: "Self-preservation Type 4s are the counter-type of Four, meaning they:", options: [{ letter: "A", text: "Are the most dramatic and emotionally expressive of all Fours" }, { letter: "B", text: "Internalize their suffering stoically, enduring pain without complaint and toughing it out rather than expressing envy openly" }, { letter: "C", text: "Focus exclusively on material wealth and possessions" }, { letter: "D", text: "Are extraverted and socially dominant" }], answer: "B", explanation: "SP Fours are called 'tenacity' (Chestnut) or 'reckless/dauntless' (Naranjo). They endure hardship without complaining, channeling envy into action rather than expression. They often look like Ones or Threes because they push through suffering instead of dwelling in it openly." },
  { id: 1382, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 132, track2Day: 182, category: "Instinctual Variants", question: "Social Type 4s express their envy differently from other Fours by:", options: [{ letter: "A", text: "Hiding it completely and appearing content with their lives" }, { letter: "B", text: "Comparing themselves unfavorably to others in a group context, often feeling like the outsider who suffers more than everyone else and making this known" }, { letter: "C", text: "Channeling it into competitive athletics" }, { letter: "D", text: "Projecting it onto others and accusing them of being envious" }], answer: "B", explanation: "Social Fours wear their suffering as a badge of identity within groups. Naranjo calls this 'shame', they compare themselves to others and always come up lacking, but paradoxically find identity in being the one who suffers most. They may unconsciously compete in 'who has it worse.'" },
  { id: 1383, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 133, track2Day: 183, category: "Instinctual Variants", question: "A sexual (SX) Type 4 in a new relationship is most likely to:", options: [{ letter: "A", text: "Maintain healthy boundaries and take things slowly" }, { letter: "B", text: "Become intensely focused on the other person, oscillating between idealization and competitive envy, demanding to be their partner's most important person" }, { letter: "C", text: "Keep things casual and avoid emotional depth" }, { letter: "D", text: "Focus on practical compatibility like shared finances and logistics" }], answer: "B", explanation: "SX Fours are the most openly competitive and demanding subtype. They experience fierce envy in relationships, wanting what others have. Chestnut notes they can be 'hate-ful', expressing frustration and demand rather than the withdrawn sadness people associate with Fours." },
  { id: 1384, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 134, track2Day: 184, category: "Wings in Practice", question: "A 4w3 and a 4w5 both feel like outsiders at a social gathering. How does each most likely respond?", options: [{ letter: "A", text: "The 4w3 channels their uniqueness into a compelling social performance; the 4w5 retreats to observe from a quiet corner" }, { letter: "B", text: "Both leave immediately" }, { letter: "C", text: "The 4w3 becomes aggressive; the 4w5 becomes clingy" }, { letter: "D", text: "Both try to blend in and act normal" }], answer: "A", explanation: "The Three wing gives 4w3s a performative edge, they transform their sense of being different into an appealing personal brand. The Five wing gives 4w5s a cerebral retreat, they intellectualize their alienation and find comfort in observation and analysis." },
  { id: 1385, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 135, track2Day: 185, category: "Wings in Practice", question: "A 4w5 is more prone to which specific mistyping compared to a 4w3?", options: [{ letter: "A", text: "Being mistyped as Type 5, because their withdrawal and intellectual depth can mask the emotional core" }, { letter: "B", text: "Being mistyped as Type 8, because they are confrontational" }, { letter: "C", text: "Being mistyped as Type 2, because they are nurturing" }, { letter: "D", text: "Being mistyped as Type 7, because they are optimistic" }], answer: "A", explanation: "4w5s can appear very Five-like: withdrawn, intellectual, minimalist, and private. The key difference is motivation: Fives withdraw to conserve energy and gain knowledge; 4w5s withdraw because the world feels inhospitable to their depth. The emotional intensity is still there, just hidden beneath layers of analysis." },
  { id: 1386, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 136, track2Day: 186, category: "Integration Paths", question: "When a Type 4 integrates toward Type 1, what practical change occurs in their daily life?", options: [{ letter: "A", text: "They become harshly self-critical and rigid" }, { letter: "B", text: "They develop discipline and structure that channels their emotional depth into consistent, principled action rather than waiting for inspiration" }, { letter: "C", text: "They lose their creativity and become conventional" }, { letter: "D", text: "They start criticizing others constantly" }], answer: "B", explanation: "Integration to 1 gives Fours access to discipline without losing their depth. Instead of creating only when 'moved,' they develop a practice. Riso-Hudson describe this as the Four becoming 'objective and principled', they channel their emotional intensity into sustained meaningful work." },
  { id: 1387, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 137, track2Day: 187, category: "Integration Paths", question: "The paradox of Type 4 integration toward Type 1 is that:", options: [{ letter: "A", text: "Ones and Fours have nothing in common, making growth impossible" }, { letter: "B", text: "The Four must accept ordinariness and routine, the very things they've always rejected, as the foundation that enables their extraordinary creative expression" }, { letter: "C", text: "The Four must abandon all emotion to become logical" }, { letter: "D", text: "Growth means the Four becomes a perfectionist about their art" }], answer: "B", explanation: "Fours often resist structure as 'inauthentic' or 'killing their creativity.' The integration paradox is that consistent practice (One energy) actually produces more and better creative work than waiting for emotional inspiration. Embracing the mundane liberates, rather than constrains, their gifts." },
  { id: 1388, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 138, track2Day: 188, category: "Cross-System", question: "Type 4s most commonly correlate with INFP in the MBTI. What cognitive function explains this connection?", options: [{ letter: "A", text: "Extraverted Sensing (Se), both love sensory experiences" }, { letter: "B", text: "Introverted Feeling (Fi), an internal values system focused on personal authenticity, emotional depth, and individual identity" }, { letter: "C", text: "Extraverted Thinking (Te), both prioritize efficient goal achievement" }, { letter: "D", text: "Introverted Thinking (Ti), both build complex logical frameworks" }], answer: "B", explanation: "Fi is the function of deep personal values, emotional authenticity, and individual identity, mapping directly onto the Four's core concerns. Fi users ask 'What do I truly feel?' and 'Is this authentic to who I am?', the same questions that drive the Four's entire orientation." },
  { id: 1389, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 139, track2Day: 189, category: "Cross-System", question: "An ESTJ Type 4 would be a rare but real combination. How would it likely manifest?", options: [{ letter: "A", text: "The person would be indistinguishable from other ESTJs" }, { letter: "B", text: "Their Te efficiency would serve their Four need for unique identity, they might build a distinctive business or organize creative projects with unusual precision" }, { letter: "C", text: "The two systems would cancel each other out, creating a bland personality" }, { letter: "D", text: "They would be constantly paralyzed by internal contradictions" }], answer: "B", explanation: "An ESTJ Four channels Te's organizational drive in service of their need for uniqueness. They might run a one-of-a-kind business, curate an unusual collection with extreme precision, or bring distinctive aesthetic sensibility to corporate environments, blending structure with individuality." },
  { id: 1390, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 140, track2Day: 190, category: "Type Dynamics", question: "When two Type 4s are in a relationship together, what is the greatest risk?", options: [{ letter: "A", text: "They'll be too logical and unemotional with each other" }, { letter: "B", text: "They may amplify each other's emotional intensity, compete over who feels more deeply, and struggle to provide the stable ground the other needs" }, { letter: "C", text: "They'll become competitive about career success" }, { letter: "D", text: "They'll avoid all emotional conversations" }], answer: "B", explanation: "Double-Four pairings can create extraordinary emotional depth but also a 'hall of mirrors' effect. Both crave being truly understood, but both also tend to focus on their own inner experience. When both are in a low mood simultaneously, neither can be the grounding presence the other needs." },
  // ── TYPE 5: The Investigator (IDs 1391–1400) ──
  { id: 1391, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 141, track2Day: 191, category: "Instinctual Variants", question: "A self-preservation Type 5 is most likely to value:", options: [{ letter: "A", text: "A wide social network and frequent entertaining" }, { letter: "B", text: "A private, self-contained living space with minimal needs, having clear walls between themselves and the world's demands" }, { letter: "C", text: "Intense romantic passion and constant emotional connection" }, { letter: "D", text: "Public recognition for their intellectual contributions" }], answer: "B", explanation: "SP Fives are the most fortress-like subtype. Naranjo calls their passion 'castle', they build physical and psychological walls to minimize their needs and dependence on others. They may live frugally, hoard resources, and maintain strict boundaries around their personal space." },
  { id: 1392, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 142, track2Day: 192, category: "Instinctual Variants", question: "Social Type 5s appear different from the stereotypical Five because they:", options: [{ letter: "A", text: "Are extraverted party animals who love being the center of attention" }, { letter: "B", text: "Seek connection through shared expertise and intellectual groups, becoming the specialist that a community relies upon" }, { letter: "C", text: "Have no interest in knowledge or ideas" }, { letter: "D", text: "Are emotionally expressive and openly vulnerable" }], answer: "B", explanation: "Social Fives are the counter-type, they connect through knowledge rather than avoiding connection. Chestnut describes them as 'totem', they earn their place in groups by becoming the essential expert. They may be surprisingly engaged socially, but always through the lens of specialized knowledge." },
  { id: 1393, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 143, track2Day: 193, category: "Instinctual Variants", question: "A sexual (SX) Type 5 in a romantic relationship is most likely to:", options: [{ letter: "A", text: "Maintain total emotional distance and never share anything personal" }, { letter: "B", text: "Form an intense, exclusive bond with one person whom they share their innermost world with, while remaining reserved with everyone else" }, { letter: "C", text: "Date many people simultaneously to avoid deep attachment" }, { letter: "D", text: "Express their feelings loudly and publicly" }], answer: "B", explanation: "SX Fives channel their limited emotional energy into one intense bond. Chestnut calls this 'confidence', they seek one person they can fully trust with their inner world. This person gets access to a surprisingly rich emotional life that the Five hides from everyone else." },
  { id: 1394, type: 5, difficulty: 2 as 1|2|3|4|5, track1Day: 144, track2Day: 194, category: "Wings in Practice", question: "How does a 5w4 differ from a 5w6 in their approach to learning?", options: [{ letter: "A", text: "The 5w4 is drawn to unconventional, creative, or abstract topics; the 5w6 gravitates toward systematic, technical, or empirical fields" }, { letter: "B", text: "The 5w4 avoids all learning; the 5w6 is obsessed with it" }, { letter: "C", text: "Both approach learning identically" }, { letter: "D", text: "The 5w4 prefers group study; the 5w6 always studies alone" }], answer: "A", explanation: "The Four wing adds emotional depth and aesthetic sensitivity, 5w4s are drawn to philosophy, art, and existential questions. The Six wing adds practicality and a desire for reliable frameworks, 5w6s prefer science, engineering, and systems with verifiable answers." },
  { id: 1395, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 145, track2Day: 195, category: "Wings in Practice", question: "In a disagreement, a 5w6 is more likely than a 5w4 to:", options: [{ letter: "A", text: "Become emotional and express hurt feelings" }, { letter: "B", text: "Cite established authorities, data, and precedents to support their position, seeking certainty through external validation of their reasoning" }, { letter: "C", text: "Withdraw entirely and refuse to discuss the matter" }, { letter: "D", text: "Make up facts to win the argument" }], answer: "B", explanation: "The Six wing adds a need for external verification that the Five's independent analysis doesn't naturally seek. 5w6s want to know their conclusions are supported by evidence and authority. 5w4s are more comfortable with purely original, unverified interpretations." },
  { id: 1396, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 146, track2Day: 196, category: "Integration Paths", question: "When a Type 5 integrates toward Type 8, what surprising change occurs?", options: [{ letter: "A", text: "They become aggressive and controlling" }, { letter: "B", text: "They move from observation to action, stepping into their body, asserting their presence, and engaging with the physical world confidently" }, { letter: "C", text: "They lose all intellectual interest" }, { letter: "D", text: "They become emotionally volatile and unpredictable" }], answer: "B", explanation: "Integration to 8 is the Five's most transformative shift. Instead of endlessly preparing and observing, they act. Riso-Hudson describe integrated Fives as becoming 'grounded and powerful', they bring their depth of knowledge into decisive, embodied action and aren't afraid to take up space." },
  { id: 1397, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 147, track2Day: 197, category: "Integration Paths", question: "A Five who has significantly integrated toward Eight would handle a workplace injustice by:", options: [{ letter: "A", text: "Researching the issue exhaustively but never speaking up" }, { letter: "B", text: "Confronting the situation directly, using their knowledge to advocate forcefully for what's right, even at personal risk" }, { letter: "C", text: "Quitting silently and finding a new job" }, { letter: "D", text: "Gossiping about it with trusted colleagues" }], answer: "B", explanation: "An integrated Five combines their deep knowledge with Eight's willingness to confront. Instead of hoarding insights, they deploy them as power, speaking truth to authority with both intellectual precision and physical presence. This is the Five moving from observer to participant." },
  { id: 1398, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 148, track2Day: 198, category: "Cross-System", question: "Type 5s most commonly correlate with INTP and INTJ. What distinguishes a Five INTP from a Five INTJ?", options: [{ letter: "A", text: "The INTP Five explores ideas for internal logical coherence (Ti); the INTJ Five builds strategic long-term visions (Ni-Te)" }, { letter: "B", text: "There is no meaningful difference between them" }, { letter: "C", text: "The INTP Five is more social; the INTJ Five is more isolated" }, { letter: "D", text: "The INTP Five prefers practical skills; the INTJ Five prefers abstract theory" }], answer: "A", explanation: "INTP Fives are driven by Ti, they want to understand how things work at a fundamental level, building internal models. INTJ Fives are driven by Ni-Te, they synthesize patterns into a strategic vision and then implement it. Both detach, but the INTP explores while the INTJ plans." },
  { id: 1399, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 149, track2Day: 199, category: "Cross-System", question: "An ESFJ Type 5 would be an extremely rare combination because:", options: [{ letter: "A", text: "ESFJs cannot exist in the Enneagram framework" }, { letter: "B", text: "Fe-Si naturally attunes to others' emotional needs and social traditions, the opposite of the Five's withdrawal and boundary-setting" }, { letter: "C", text: "ESFJs are too unintelligent to be Fives" }, { letter: "D", text: "Sensing types cannot be any head-center type" }], answer: "B", explanation: "Fe dominant types orient outward toward social harmony and others' emotional states, a fundamentally different orientation from the Five's core drive to withdraw, conserve, and observe from a distance. An ESFJ Five would experience significant internal tension between their function stack's social pull and their type's need for detachment." },
  { id: 1400, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 150, track2Day: 200, category: "Type Dynamics", question: "When a Type 5 and Type 8 work together on a project, what complementary dynamic often emerges?", options: [{ letter: "A", text: "They clash constantly because they have nothing in common" }, { letter: "B", text: "The Five provides deep strategic analysis while the Eight drives decisive implementation, but tension arises when the Eight moves too fast for the Five's comfort" }, { letter: "C", text: "The Five dominates and the Eight follows passively" }, { letter: "D", text: "Both withdraw and nothing gets done" }], answer: "B", explanation: "Fives and Eights share a directness and dislike of emotional manipulation. The Five brings intellectual depth; the Eight brings action and force. The friction point is pace: Eights want to act now, Fives want more data first. When balanced, they form a powerful think-then-act partnership." },
  // ── TYPE 6: The Loyalist (IDs 1401–1410) ──
  { id: 1401, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 151, track2Day: 201, category: "Instinctual Variants", question: "A self-preservation Type 6 expresses their anxiety primarily through:", options: [{ letter: "A", text: "Bold confrontation of perceived threats" }, { letter: "B", text: "Creating warmth, alliances, and security systems, befriending potential threats and ensuring they have a reliable support network" }, { letter: "C", text: "Intellectual analysis of abstract philosophical problems" }, { letter: "D", text: "Pursuing intense romantic relationships for emotional security" }], answer: "B", explanation: "SP Sixes manage fear through building a warm, reliable safety net. Chestnut calls this 'warmth', they befriend people who might be threats, secure their physical environment, and create loyalty bonds. They often appear friendly and approachable, masking anxiety with affiliative behavior." },
  { id: 1402, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 152, track2Day: 202, category: "Instinctual Variants", question: "Social Type 6s often look like which other Enneagram type, and why?", options: [{ letter: "A", text: "Type 1, because they become rigid enforcers of group rules, using ideological certainty to manage their inner doubt" }, { letter: "B", text: "Type 4, because they become withdrawn and melancholic" }, { letter: "C", text: "Type 7, because they become scattered and pleasure-seeking" }, { letter: "D", text: "Type 3, because they become image-conscious and competitive" }], answer: "A", explanation: "Social Sixes combat doubt by aligning with clear rules, ideologies, or authority systems. Naranjo calls this 'duty', they become zealous defenders of the group's code. This rigidity can look like One-ish perfectionism, but the motivation is security through belonging, not moral correctness." },
  { id: 1403, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 153, track2Day: 203, category: "Instinctual Variants", question: "Sexual (SX) Type 6s are the most counter-phobic subtype. In practice, this means they:", options: [{ letter: "A", text: "Are the most anxious and avoidant of all Sixes" }, { letter: "B", text: "Confront their fears head-on through intimidation, physical intensity, or deliberately seeking out what frightens them" }, { letter: "C", text: "Are completely fearless and never experience anxiety" }, { letter: "D", text: "Channel their anxiety into helping others feel safe" }], answer: "B", explanation: "SX Sixes move against fear rather than away from it. They may seek out dangerous sports, confront authority, or adopt an intimidating persona. Chestnut describes them as looking like Eights, fierce and confrontational, but underneath is the Six's anxiety being managed through offensive action." },
  { id: 1404, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 154, track2Day: 204, category: "Wings in Practice", question: "A 6w5 facing a major life decision is most likely to:", options: [{ letter: "A", text: "Make a quick gut decision and move on" }, { letter: "B", text: "Research exhaustively, create mental models of every scenario, and still struggle to commit because more information might change the calculus" }, { letter: "C", text: "Ask everyone they know for their opinion and go with the majority" }, { letter: "D", text: "Flip a coin because they believe in fate" }], answer: "B", explanation: "The Five wing amplifies the Six's analytical side. 6w5s intellectualize their anxiety, they believe that enough data will create certainty. But the Six's fundamental doubt means no amount of research feels sufficient, creating analysis paralysis that 6w7s typically avoid through action." },
  { id: 1405, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 155, track2Day: 205, category: "Wings in Practice", question: "How does a 6w7 manage anxiety differently from a 6w5?", options: [{ letter: "A", text: "The 6w7 distracts from anxiety through activity, humor, and social engagement, staying busy to outrun their fears rather than analyzing them" }, { letter: "B", text: "The 6w7 has no anxiety at all" }, { letter: "C", text: "The 6w7 becomes more withdrawn and isolated" }, { letter: "D", text: "The 6w7 handles anxiety identically to the 6w5 but in social settings" }], answer: "A", explanation: "The Seven wing provides an escape valve for the Six's anxiety. 6w7s use humor, activity, and optimism to keep fear at bay, they're often the funny, engaging friend who is secretly running worst-case scenarios underneath. They manage anxiety by staying in motion rather than sitting with it." },
  { id: 1406, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 156, track2Day: 206, category: "Integration Paths", question: "When a Type 6 integrates toward Type 9, what healthy shift occurs?", options: [{ letter: "A", text: "They become passive and disengaged from life" }, { letter: "B", text: "They develop inner calm and learn to trust themselves and the world, finding peace without needing constant reassurance or vigilance" }, { letter: "C", text: "They become even more anxious about maintaining peace" }, { letter: "D", text: "They lose their ability to perceive real threats" }], answer: "B", explanation: "Integration to 9 gives Sixes access to the Nine's groundedness and inner peace. Instead of scanning for danger, they relax into trust. Riso-Hudson describe this as the Six becoming 'more relaxed and optimistic', they discover that the world is mostly safe and they can handle what comes." },
  { id: 1407, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 157, track2Day: 207, category: "Integration Paths", question: "The growth challenge unique to Six's integration toward Nine is:", options: [{ letter: "A", text: "Learning to be more productive and efficient" }, { letter: "B", text: "Distinguishing between genuine inner peace and the Six's tendency to find false comfort in new authority figures or belief systems that merely replace old ones" }, { letter: "C", text: "Becoming more socially outgoing" }, { letter: "D", text: "Developing better analytical skills" }], answer: "B", explanation: "Sixes can mistake 'finding a new guru' for genuine inner peace. True Nine integration means the Six trusts their own inner authority, not just a different external one. The growth edge is developing self-trust that doesn't depend on any system, teacher, or ideology." },
  { id: 1408, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 158, track2Day: 208, category: "Cross-System", question: "Type 6s are one of the most evenly distributed types across MBTI categories. Why?", options: [{ letter: "A", text: "Because Six is the most common Enneagram type, so it correlates with everything" }, { letter: "B", text: "Because the Six's core pattern of vigilance, loyalty, and doubt can manifest through any cognitive function, a Te Six enforces procedures, an Fi Six doubts their own values, an Ne Six imagines catastrophes" }, { letter: "C", text: "Because the MBTI and Enneagram are completely unrelated systems" }, { letter: "D", text: "Because Sixes are chameleons who change their MBTI type frequently" }], answer: "B", explanation: "Six is defined by a relationship to authority and security, not by a specific cognitive style. An ISFJ Six and an ENTP Six look very different but share the core pattern of testing, questioning, and seeking certainty. The doubt can operate through any function: Si doubts through precedent, Ne through possibilities, Ti through logic." },
  { id: 1409, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 159, track2Day: 209, category: "Cross-System", question: "A counter-phobic ESTP Type 6 might be mistaken for a Type 8 in both systems. The clearest distinguishing factor is:", options: [{ letter: "A", text: "Physical size and strength" }, { letter: "B", text: "The ESTP Six's aggression masks underlying anxiety, they need to prove they're not afraid, while an Eight's assertiveness comes from genuine gut-level certainty and desire for control" }, { letter: "C", text: "Eights are always introverted and Sixes are always extraverted" }, { letter: "D", text: "There is no meaningful difference" }], answer: "B", explanation: "The counter-phobic Six charges toward fear to prove they can handle it, their toughness is reactive. The Eight's forcefulness is proactive, they naturally fill space and assert control without needing to prove anything. Under stress, the Six's bravado may crack, revealing anxiety; the Eight's may intensify into domination." },
  { id: 1410, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 160, track2Day: 210, category: "Type Dynamics", question: "Type 6s often have a complicated dynamic with Type 8 bosses. What typically happens?", options: [{ letter: "A", text: "They immediately become best friends due to shared values" }, { letter: "B", text: "The Six initially seeks the Eight's protection and decisiveness, but eventually tests the Eight's authority to determine if they're truly trustworthy, which the Eight may perceive as disloyalty" }, { letter: "C", text: "The Six ignores the Eight completely" }, { letter: "D", text: "The Eight becomes submissive to the Six's questioning" }], answer: "B", explanation: "This is one of the Enneagram's most complex authority dynamics. Sixes want strong, trustworthy leaders but compulsively test them. Eights want loyalty and detest questioning. The Six's testing feels like betrayal to the Eight; the Eight's anger at being questioned confirms the Six's fear that authority is dangerous." },
  // ── TYPE 7: The Enthusiast (IDs 1411–1420) ──
  { id: 1411, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 161, track2Day: 211, category: "Instinctual Variants", question: "Self-preservation Type 7s express their gluttony through:", options: [{ letter: "A", text: "Reckless, death-defying physical adventures" }, { letter: "B", text: "Creating practical networks of opportunity, having multiple income streams, backup plans, and a web of connections that ensure they'll always land on their feet" }, { letter: "C", text: "Intense focus on a single passionate relationship" }, { letter: "D", text: "Pursuing spiritual enlightenment and rejecting material comforts" }], answer: "B", explanation: "SP Sevens are the most grounded subtype, focused on practical opportunities and material security. Naranjo calls their fixation 'family' or 'keepers of the castle', they build networks of mutual advantage. They can look like industrious Threes or security-focused Sixes." },
  { id: 1412, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 162, track2Day: 212, category: "Instinctual Variants", question: "Social Type 7s are often described as sacrificing personal pleasure for a cause. How does this manifest?", options: [{ letter: "A", text: "They completely abandon their Seven nature and become ascetic" }, { letter: "B", text: "They channel their enthusiasm into serving the group, becoming idealistic leaders who reframe sacrifice as an exciting mission, hiding their gluttony behind altruism" }, { letter: "C", text: "They become withdrawn and antisocial" }, { letter: "D", text: "They help others purely for recognition and applause" }], answer: "B", explanation: "Social Sevens are the counter-type. Chestnut calls this 'sacrifice', they suppress personal desires to serve a larger cause, but still approach service with Seven enthusiasm and optimism. They may look like Twos, but their motivation is avoiding guilt through contribution, not seeking love through helping." },
  { id: 1413, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 163, track2Day: 213, category: "Instinctual Variants", question: "A sexual (SX) Type 7 approaches a potential romantic interest by:", options: [{ letter: "A", text: "Carefully analyzing compatibility before making a move" }, { letter: "B", text: "Seeing the world through rose-colored glasses, imagining an idealized future together, and pursuing with infectious enthusiasm that can overwhelm the other person" }, { letter: "C", text: "Playing it cool and maintaining emotional distance" }, { letter: "D", text: "Performing acts of service to win them over slowly" }], answer: "B", explanation: "SX Sevens are the dreamers of the Seven subtypes. They idealize potential partners and experiences with intense optimism. Naranjo connects this to 'suggestibility', they see possibilities rather than realities in people. This can create intoxicating early romance but disappointing reality checks later." },
  { id: 1414, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 164, track2Day: 214, category: "Wings in Practice", question: "The key difference between a 7w6 and a 7w8 in a group project is:", options: [{ letter: "A", text: "The 7w6 is collaborative and seeks group consensus before acting; the 7w8 is more independently decisive and willing to push their vision through resistance" }, { letter: "B", text: "The 7w6 does all the work; the 7w8 does nothing" }, { letter: "C", text: "Both behave identically in group settings" }, { letter: "D", text: "The 7w6 is more creative; the 7w8 is more logical" }], answer: "A", explanation: "The Six wing makes 7w6s more affiliative and team-oriented, they want buy-in and shared enthusiasm. The Eight wing makes 7w8s more forceful and independent, they'll take charge and push forward even if others aren't on board. Both are energetic, but 7w6s seek agreement while 7w8s seek results." },
  { id: 1415, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 165, track2Day: 215, category: "Wings in Practice", question: "A 7w8 is most commonly mistyped as which type, and what distinguishes them?", options: [{ letter: "A", text: "Type 8, because they share directness and intensity, but the 7w8 is driven by the desire for stimulating experiences while the 8 is driven by the desire for control and autonomy" }, { letter: "B", text: "Type 3, because they are both productive" }, { letter: "C", text: "Type 2, because they are both warm" }, { letter: "D", text: "Type 4, because they are both creative" }], answer: "A", explanation: "7w8s combine Seven's appetite for experience with Eight's forcefulness, creating a powerfully assertive personality. The distinction lies in core motivation: 7w8s pursue experiences and possibilities (escaping limitation), while 8s pursue control and self-determination (escaping vulnerability)." },
  { id: 1416, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 166, track2Day: 216, category: "Integration Paths", question: "When a Type 7 integrates toward Type 5, what does healthy growth look like?", options: [{ letter: "A", text: "They become isolated and lose their enthusiasm" }, { letter: "B", text: "They develop the ability to go deep into one topic, sit with difficult feelings, and find satisfaction in focused mastery rather than constant novelty" }, { letter: "C", text: "They become paranoid and suspicious of others" }, { letter: "D", text: "They stop having fun entirely" }], answer: "B", explanation: "Integration to 5 gives Sevens access to depth and focus. Instead of sampling everything, they discover that mastery of one thing is more satisfying than dabbling in twenty. Riso-Hudson describe integrated Sevens as becoming 'fascinated by profound reality' rather than fleeing into pleasant fantasy." },
  { id: 1417, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 167, track2Day: 217, category: "Integration Paths", question: "The deepest challenge in the Seven's integration toward Five is:", options: [{ letter: "A", text: "Learning to multitask more effectively" }, { letter: "B", text: "Staying present with pain, boredom, and emptiness without reframing them into something positive or escaping into the next plan" }, { letter: "C", text: "Becoming more socially skilled" }, { letter: "D", text: "Reading more books" }], answer: "B", explanation: "The Seven's entire defense structure is built on reframing negative experiences into positive ones. Five integration asks them to stop, to sit in discomfort without narrating it away. This means feeling grief as grief, boredom as boredom, and emptiness as emptiness. It is profoundly difficult because it dissolves their primary coping mechanism." },
  { id: 1418, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 168, track2Day: 218, category: "Cross-System", question: "Type 7s most commonly test as ENFP or ENTP. What cognitive function underlies this pattern?", options: [{ letter: "A", text: "Introverted Sensing (Si), a focus on past positive experiences" }, { letter: "B", text: "Extraverted Intuition (Ne), the rapid generation of possibilities, connections, and alternatives that mirrors the Seven's mental pattern of planning and reframing" }, { letter: "C", text: "Extraverted Feeling (Fe), attunement to group emotions" }, { letter: "D", text: "Introverted Thinking (Ti), careful logical analysis" }], answer: "B", explanation: "Ne is the function of possibility, it sees connections between disparate ideas and generates alternatives rapidly. This maps perfectly to the Seven's mental habit of generating options, seeing silver linings, and connecting unrelated topics. Both Ne and Seven energy resist being pinned down to a single interpretation." },
  { id: 1419, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 169, track2Day: 219, category: "Cross-System", question: "An ISTJ Type 7 would be rare. If one existed, what internal conflict would define their experience?", options: [{ letter: "A", text: "No conflict, MBTI and Enneagram operate independently" }, { letter: "B", text: "Their Si-Te function stack craves routine, precedent, and proven methods while their Seven core craves novelty and possibility, creating a person who builds elaborate structured plans for adventures" }, { letter: "C", text: "They would simply not be a real Seven" }, { letter: "D", text: "They would be indistinguishable from an ISTJ Six" }], answer: "B", explanation: "An ISTJ Seven would channel their desire for new experiences through Si-Te's structured lens, perhaps meticulously planning varied vacations, building detailed itineraries for adventures, or systematically working through a bucket list. The Seven desire for stimulation would operate within the ISTJ's need for order." },
  { id: 1420, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 170, track2Day: 220, category: "Type Dynamics", question: "When a Type 7 and Type 1 are in a committed relationship, what growth opportunity does each provide the other?", options: [{ letter: "A", text: "None, they are completely incompatible" }, { letter: "B", text: "The Seven teaches the One to lighten up and embrace imperfection; the One teaches the Seven to follow through and find depth in commitment, each embodies the other's integration point" }, { letter: "C", text: "The Seven teaches the One to avoid responsibility; the One teaches the Seven to be more rigid" }, { letter: "D", text: "They only reinforce each other's weaknesses" }], answer: "B", explanation: "This is a reciprocal integration pairing: Ones integrate toward 7, Sevens integrate toward 5 (not 1 directly, but Ones model discipline). The One helps the Seven commit and complete things; the Seven helps the One access joy and spontaneity. At their best, they balance discipline with delight." },
  // ── TYPE 8: The Challenger (IDs 1421–1430) ──
  { id: 1421, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 171, track2Day: 221, category: "Instinctual Variants", question: "Self-preservation Type 8s express their lust (excess) through:", options: [{ letter: "A", text: "Social dominance and controlling group dynamics" }, { letter: "B", text: "Satisfying material and physical needs with gusto, they ensure they and their people have enough food, money, comfort, and security, and become fiercely protective providers" }, { letter: "C", text: "Pursuing intense romantic conquests" }, { letter: "D", text: "Intellectual dominance in debates" }], answer: "B", explanation: "SP Eights channel their intensity into material survival and provision. Naranjo calls this 'survival' or 'satisfactory survival', they are the providers who make sure their tribe has more than enough. They may look less aggressive than other Eights because their force is channeled into practical caretaking." },
  { id: 1422, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 172, track2Day: 222, category: "Instinctual Variants", question: "Social Type 8s often channel their energy into:", options: [{ letter: "A", text: "Quiet personal reflection and meditation" }, { letter: "B", text: "Protecting the underdog and fighting systemic injustice, they use their power on behalf of groups rather than purely personal interests" }, { letter: "C", text: "Building personal wealth and luxury" }, { letter: "D", text: "Avoiding group dynamics and working alone" }], answer: "B", explanation: "Social Eights direct their protective instinct outward toward communities. Chestnut calls this 'social duty', they become champions of the weak, fighting against corrupt systems. They can look like Ones (principled reformers) or Twos (protectors), but the Eight's directness and intensity remains." },
  { id: 1423, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 173, track2Day: 223, category: "Instinctual Variants", question: "A sexual (SX) Type 8 in a close relationship is most likely to:", options: [{ letter: "A", text: "Maintain emotional distance and control" }, { letter: "B", text: "Seek total possession and emotional intensity, wanting to fully own and be owned by their partner in a consuming, all-or-nothing bond" }, { letter: "C", text: "Be passive and accommodating to their partner's wishes" }, { letter: "D", text: "Treat the relationship as a practical arrangement without emotion" }], answer: "B", explanation: "SX Eights are the most emotionally intense subtype. They seek a kind of fusion with their partner, wanting to possess and be possessed completely. Naranjo connects this to 'possession', they can be charismatic, magnetic, and overwhelming in their desire for total intimacy." },
  { id: 1424, type: 8, difficulty: 2 as 1|2|3|4|5, track1Day: 174, track2Day: 224, category: "Wings in Practice", question: "How does an 8w7 differ from an 8w9 in their leadership style?", options: [{ letter: "A", text: "The 8w7 leads with high energy, charisma, and bold vision; the 8w9 leads with calm authority, patience, and steady presence" }, { letter: "B", text: "The 8w7 avoids leadership; the 8w9 seeks it aggressively" }, { letter: "C", text: "Both lead identically" }, { letter: "D", text: "The 8w7 is more intellectual; the 8w9 is more emotional" }], answer: "A", explanation: "The Seven wing amplifies the Eight's energy, 8w7s are the 'Mavericks,' bold and expansive. The Nine wing tempers the Eight's intensity, 8w9s are the 'Bears,' powerful but calm until provoked. Both command respect, but the 8w7 does it through force of personality and the 8w9 through quiet gravitas." },
  { id: 1425, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 175, track2Day: 225, category: "Wings in Practice", question: "An 8w9 is sometimes called 'the most dangerous Eight' because:", options: [{ letter: "A", text: "They are physically larger and stronger" }, { letter: "B", text: "Their Nine wing provides patience and a deceptively calm exterior, meaning they absorb provocation for a long time before responding with devastating, well-considered force" }, { letter: "C", text: "They are more aggressive than 8w7s in all situations" }, { letter: "D", text: "They use weapons rather than words" }], answer: "B", explanation: "While 8w7s show their force immediately, 8w9s combine Eight's power with Nine's patience. They seem calm and easygoing until a line is crossed, then their response is proportional to all the accumulated pressure. Others underestimate them because the Nine wing masks the Eight's intensity until it's too late." },
  { id: 1426, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 176, track2Day: 226, category: "Integration Paths", question: "When a Type 8 integrates toward Type 2, what healthy transformation occurs?", options: [{ letter: "A", text: "They become people-pleasing and lose their strength" }, { letter: "B", text: "They learn to use their power in service of others, becoming nurturing protectors who can be vulnerable and tender with those they love" }, { letter: "C", text: "They become manipulative and controlling through gifts" }, { letter: "D", text: "They stop being assertive entirely" }], answer: "B", explanation: "Integration to 2 is the Eight's softening. Instead of power for control, they discover power for care. Riso-Hudson describe integrated Eights as becoming 'magnanimous and caring', they protect and empower others rather than dominating them. They allow themselves to need people, which they find terrifying." },
  { id: 1427, type: 8, difficulty: 5 as 1|2|3|4|5, track1Day: 177, track2Day: 227, category: "Integration Paths", question: "For a Type 8, the most vulnerable moment in their growth journey toward Two is:", options: [{ letter: "A", text: "Making more money and gaining more influence" }, { letter: "B", text: "Admitting that they have tender feelings and need others, exposing the soft underbelly they've spent their life armoring against" }, { letter: "C", text: "Learning to argue more effectively" }, { letter: "D", text: "Becoming more physically imposing" }], answer: "B", explanation: "Eights build their entire identity on self-sufficiency and invulnerability. Two integration requires them to say 'I need you' and 'This hurts me', words that feel like existential threats. Palmer notes that the Eight's deepest fear is that vulnerability will be exploited, so showing tenderness requires extraordinary courage." },
  { id: 1428, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 178, track2Day: 228, category: "Cross-System", question: "Type 8s most commonly correlate with ENTJ and ESTJ. What makes the ENTJ-Eight combination particularly powerful?", options: [{ letter: "A", text: "Ni-Te provides both strategic vision and execution drive, amplifying the Eight's natural ability to see the big picture and command resources to achieve it" }, { letter: "B", text: "ENTJs are always Type 8, so the combination is unremarkable" }, { letter: "C", text: "ENTJs are too cerebral to be Eights" }, { letter: "D", text: "The combination makes them less effective because the systems conflict" }], answer: "A", explanation: "ENTJ Eights combine Ni's long-range strategic vision with Te's ability to organize and execute, layered on top of the Eight's gut-driven force and protectiveness. They become natural empire-builders who can envision a goal, command the resources, and drive through obstacles, one of the most formidable leadership profiles." },
  { id: 1429, type: 8, difficulty: 5 as 1|2|3|4|5, track1Day: 179, track2Day: 229, category: "Cross-System", question: "An INFP Type 8 would be an unusual combination. How might their Fi dominance reshape the typical Eight pattern?", options: [{ letter: "A", text: "Fi would eliminate the Eight's assertiveness entirely" }, { letter: "B", text: "Their forcefulness would be directed toward defending deeply personal values and protecting individual authenticity, they would fight fiercely for what they believe in on a personal, values-level rather than for territorial control" }, { letter: "C", text: "They would be indistinguishable from an INFP Four" }, { letter: "D", text: "The combination is impossible" }], answer: "B", explanation: "An INFP Eight channels the Eight's intensity through Fi's deep personal values. Instead of fighting for power or control, they fight for authenticity and individual freedom. They might be quiet until a personal value is violated, then display surprising forcefulness, a warrior for inner truth rather than outer dominance." },
  { id: 1430, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 180, track2Day: 230, category: "Type Dynamics", question: "When Type 8 and Type 2 are in a relationship, what complementary dynamic often emerges, and where does it become problematic?", options: [{ letter: "A", text: "They have nothing in common and the relationship fails immediately" }, { letter: "B", text: "The Eight provides protection and strength while the Two provides warmth and emotional attunement, but it becomes toxic when the Eight dominates and the Two enables, creating a power imbalance neither acknowledges" }, { letter: "C", text: "The Two dominates and the Eight becomes passive" }, { letter: "D", text: "Both avoid emotional expression entirely" }], answer: "B", explanation: "The 8-2 pairing is common because each offers what the other craves: the Eight gets nurturing without having to ask; the Two gets a powerful protector. The shadow side is codependency, the Eight may become controlling while the Two martyrs themselves, and neither addresses the underlying power dynamic directly." },
  // ── TYPE 9: The Peacemaker (IDs 1431–1440) ──
  { id: 1431, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 181, track2Day: 231, category: "Instinctual Variants", question: "Self-preservation Type 9s express their sloth (self-forgetting) through:", options: [{ letter: "A", text: "Dramatic emotional outbursts and constant conflict" }, { letter: "B", text: "Physical comfort-seeking, using food, sleep, routine, and sensory pleasure to numb themselves from the discomfort of asserting their own priorities" }, { letter: "C", text: "Intense workaholism and career ambition" }, { letter: "D", text: "Constant social activity and party-going" }], answer: "B", explanation: "SP Nines are the most concrete expression of sloth. They narcotize through physical comforts, a good meal, a warm blanket, a familiar routine. Naranjo calls this 'appetite', they substitute physical satisfaction for the more demanding work of pursuing their own desires and ambitions." },
  { id: 1432, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 182, track2Day: 232, category: "Instinctual Variants", question: "Social Type 9s often appear surprisingly energetic and engaged. This is because they:", options: [{ letter: "A", text: "Have overcome their Nine tendencies entirely" }, { letter: "B", text: "Merge with group energy and agendas, becoming hard workers who pour themselves into the collective while neglecting their own individual wants" }, { letter: "C", text: "Are actually mistyped Threes" }, { letter: "D", text: "Only pretend to be engaged while internally checked out" }], answer: "B", explanation: "Social Nines are the counter-type, they look active and involved because they merge with group energy. Chestnut calls this 'participation', they can be tireless workers for a cause or community, but the sloth shows in their neglect of personal priorities. They know what the group needs but not what they want." },
  { id: 1433, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 183, track2Day: 233, category: "Instinctual Variants", question: "A sexual (SX) Type 9 often looks like which other type, and why?", options: [{ letter: "A", text: "Type 8, because they are aggressive and confrontational" }, { letter: "B", text: "Type 4, because they merge with their partner's identity, taking on the other person's interests, aesthetics, and emotional world as if it were their own" }, { letter: "C", text: "Type 5, because they are intellectually detached" }, { letter: "D", text: "Type 1, because they are rigid and principled" }], answer: "B", explanation: "SX Nines merge with their beloved, adopting the partner's hobbies, style, opinions, and emotional landscape. This fusion can look like the Four's intensity in relationships. Chestnut calls this 'fusion', the Nine disappears into the other person, which feels like love but is actually self-forgetting taken to an extreme." },
  { id: 1434, type: 9, difficulty: 2 as 1|2|3|4|5, track1Day: 184, track2Day: 234, category: "Wings in Practice", question: "What is the most visible behavioral difference between a 9w8 and a 9w1?", options: [{ letter: "A", text: "The 9w8 has a stubborn, immovable quality and can surprise people with sudden bluntness; the 9w1 is more quietly principled and critical, expressing displeasure through passive resistance" }, { letter: "B", text: "The 9w8 is always angry; the 9w1 is always calm" }, { letter: "C", text: "There is no observable difference" }, { letter: "D", text: "The 9w8 is more intellectual; the 9w1 is more physical" }], answer: "A", explanation: "The Eight wing gives 9w8s surprising bursts of force, they're easygoing until pushed, then shockingly direct. The One wing gives 9w1s a quiet moral backbone, they seem agreeable but hold firm to internal standards, expressing disagreement through passive-aggressive withdrawal rather than confrontation." },
  { id: 1435, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 185, track2Day: 235, category: "Wings in Practice", question: "A 9w1 is most likely to be mistyped as which type, and what reveals their true Nine-ness?", options: [{ letter: "A", text: "Type 1, because they share orderliness and ethics, but the 9w1 avoids conflict even about things they care deeply about, while a true One confronts violations of their standards" }, { letter: "B", text: "Type 7, because they seem fun and carefree" }, { letter: "C", text: "Type 3, because they are ambitious and driven" }, { letter: "D", text: "Type 8, because they are forceful and direct" }], answer: "A", explanation: "9w1s share the One's desire for things to be 'right' but lack the One's willingness to confront. A true One will speak up when standards are violated; a 9w1 will silently simmer. The tell is conflict avoidance: if someone has strong opinions but consistently fails to voice them, they may be a 9w1 rather than a 1." },
  { id: 1436, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 186, track2Day: 236, category: "Integration Paths", question: "When a Type 9 integrates toward Type 3, what does healthy growth look like?", options: [{ letter: "A", text: "They become image-conscious and superficial" }, { letter: "B", text: "They develop self-worth independent of others, set personal goals, and take decisive action toward what they genuinely want, stepping into their own spotlight" }, { letter: "C", text: "They become competitive and cutthroat" }, { letter: "D", text: "They start bragging about their accomplishments" }], answer: "B", explanation: "Integration to 3 helps Nines answer the question they've been avoiding: 'What do I want?' Instead of merging with others' agendas, they develop their own goals and pursue them with energy. Riso-Hudson describe integrated Nines as becoming 'self-developing and energetic', they discover their own value and ambition." },
  { id: 1437, type: 9, difficulty: 5 as 1|2|3|4|5, track1Day: 187, track2Day: 237, category: "Integration Paths", question: "The most difficult aspect of the Nine's integration journey toward Three is:", options: [{ letter: "A", text: "Learning to relax and go with the flow" }, { letter: "B", text: "Tolerating the anxiety and potential conflict that comes from having visible, personal desires, because wanting something specific means risking rejection, failure, and separation from others" }, { letter: "C", text: "Becoming more agreeable and accommodating" }, { letter: "D", text: "Developing a wider social network" }], answer: "B", explanation: "Nines merge and self-forget because having personal wants feels dangerous, it creates the possibility of conflict and separation. Three integration asks them to stand apart, be seen, and want things loudly. This risks the very disconnection Nines most fear, which is why it requires tremendous courage." },
  { id: 1438, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 188, track2Day: 238, category: "Cross-System", question: "Type 9s commonly test as ISFP or INFP in the MBTI. What function creates the overlap?", options: [{ letter: "A", text: "Extraverted Thinking (Te), the drive to organize the external world" }, { letter: "B", text: "Introverted Feeling (Fi), a deep but privately held value system that resists external imposition, mirroring the Nine's quiet inner world and resistance to being controlled" }, { letter: "C", text: "Extraverted Sensing (Se), the love of physical thrills and adventure" }, { letter: "D", text: "Extraverted Intuition (Ne), the generation of multiple possibilities" }], answer: "B", explanation: "Fi's quiet, internally referenced value system matches the Nine's deep but often unexpressed inner life. Both IxFPs and Nines may appear agreeable on the surface while holding firm inner convictions they rarely voice. The key parallel is passive resistance, neither aggressively imposes their will but neither truly abandons their values." },
  { id: 1439, type: 9, difficulty: 5 as 1|2|3|4|5, track1Day: 189, track2Day: 239, category: "Cross-System", question: "An ENTJ Type 9 would be an unusual combination. What internal experience might define them?", options: [{ letter: "A", text: "They would simply be a normal ENTJ with no Nine characteristics" }, { letter: "B", text: "Their Te-Ni would drive them to lead and strategize, but their Nine core would create an inner conflict, achieving externally while internally feeling disconnected from whether these achievements truly reflect their own wants" }, { letter: "C", text: "The combination is impossible" }, { letter: "D", text: "They would be the most peaceful, least assertive ENTJ" }], answer: "B", explanation: "An ENTJ Nine would look successful and decisive externally, Te-Ni naturally organizes and strategizes. But the Nine core means their goals may actually be borrowed from others' expectations. They might build an impressive career and then wonder 'Is this what I actually wanted?', achieving without true self-authoring." },
  { id: 1440, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 190, track2Day: 240, category: "Type Dynamics", question: "When two Type 9s form a close relationship, what is the characteristic strength and vulnerability of this pairing?", options: [{ letter: "A", text: "They fight constantly because they are both stubborn" }, { letter: "B", text: "They create a warm, harmonious bond with deep mutual acceptance, but may drift into inertia, avoiding difficult conversations and enabling each other's tendency to numb out and coast" }, { letter: "C", text: "One Nine always dominates while the other submits" }, { letter: "D", text: "They have no emotional connection because both are detached" }], answer: "B", explanation: "Double-Nine pairings are among the most comfortable in the Enneagram, both value peace, acceptance, and low conflict. The danger is mutual narcotization: neither pushes the other to grow, confront issues, or pursue individual desires. They can create a beautiful, warm stasis that feels like contentment but may actually be shared avoidance." },
];
